import{_ as i,o as e,c as a,a as t}from"./chunks/plugin-vue_export-helper.CrIAyUQY.js";const d=JSON.parse('{"title":"Выбор стека технологий (введение и кейсы)","description":"","frontmatter":{"title":"Выбор стека технологий (введение и кейсы)","date":"2022-11-03T00:00:00.000Z","permalink":"/stack-1"},"headers":[],"relativePath":"posts/2022-11-03-my-next-project.md","filePath":"posts/2022-11-03-my-next-project.md"}'),r={name:"posts/2022-11-03-my-next-project.md"};function o(p,l,c,n,h,s){return e(),a("div",null,[...l[0]||(l[0]=[t('<p>Речь пойдет о выборе и использовании fullstack-инструментария после 10 лет занятия разработкой на проектах, из которых с нуля я начинал только 2.</p><p>Стек технологий очень важен, он выбирается один раз на всю жизнь проекта, а некоторые проекты вдруг обнаруживают что заменить mongodb на postgresql когда база данных уже весит несколько гигабайт и активно используется очень дорого, а найти разработчиков со знанием graphql очень сложно.</p><p>Поэтому при выборе очень часто принято отталкиваться от рынка. Ведь правда - чем больше хайпа вокруг фреймворка, тем проще на нем разрабатывать и искать исполнителей.</p><p>Я люблю Ruby on Rails, но выбрать его для нового проекта я бы не хотел, потому что замена разработчика будет стоить очень дорого.</p><p>Как бы мне не был отвратителен React и как бы у меня не болели глаза от миллионов строк кода, которые я увидел, выбирать Vue и Angular тоже довольно рискованно ввиду ригидности этих технологий.</p><p>Стек технологий обычно содержит</p><ul><li>хранилище данных - это база данных и файловое хранилище <ul><li>базы данных <ul><li>Postgres</li><li>MS SQL</li><li>Elasticsearch</li><li>MongoDB</li><li>memcached,</li><li>Redis</li><li>etc...</li></ul></li><li>хранилища <ul><li>minio</li><li>S3</li><li>RAS</li></ul></li></ul></li><li>бэкенд-фреймворк - его выбор зависит от ландшафта и требований, обычно содержит ORM - синтаксический сахар над SQL-запросами. <ul><li>Django (Python)</li><li>Ruby on Rails</li><li>ExpressJS (Nest, Next, Nuxt, Meteor)</li><li>Lavarel (PHP)</li><li>.Net core</li><li>Spring (Java)</li><li>Jamstack - Headless CMS (Strapi, Contentful, Gatsby) - пользовательский интерфейс для создания и изменения структур контента</li></ul></li><li>фронтенд-фреймворк - его выбор зависит от набора компонентов пользовательского интерфейса и количества и динамичности данных которые будут обрабатываться на фронтенде. <ul><li>React</li><li>Angular</li><li>Vue</li><li>Ember</li><li>Svelte</li><li>Tooling - typescript, eslint, prettier, webpack, turbopack, etc...</li><li>кроме прочего, нужно выбрать библиотеку компонент и css-framework (tailwind, bootstrap, foundation)</li></ul></li><li>системы виртуализации-контейнеризации <ul><li>Docker (kubernetes)</li><li>VMWare</li></ul></li><li>API (внутренний или внешний программный интерфейс для интеграции), например: <ul><li>Graphql</li><li>Kafka</li><li>Twilio</li><li>Auth0</li></ul></li></ul><p>Также, в зависимости от требований проекта, необходимо заранее задуматься об инфраструктуре и процессе деплоя приложения</p><ul><li>CI/CD</li><li>мониторинг (prometheus, graphana)</li><li>парсер логов (kibana) и выписать конкретные показатели которые необходимо отслеживать и ранжировать по критичности.</li></ul><p>Итак, для того чтобы выбрать стек, нужно определить проблему. Затем нужно определить ландшафт и данные, которые мы будем хранить и обрабатывать.</p><p>Возьмем для примера несколько кейсов из PropTech, EdTech, FinTech и HR-Tech.</p><h2 id="кеис-1-edtech" tabindex="-1">Кейс 1. EdTech <a class="header-anchor" href="#кеис-1-edtech" aria-label="Permalink to &quot;Кейс 1. EdTech&quot;">​</a></h2><p>Необходимо создать систему тестирования учащихся (без уточнения - школ, вузов, онлайн-курсов) с возможностью проведения нескольких видов тестов:</p><ul><li>тест на выбор правильного ответа</li><li>тест со свободным полем ввода</li><li>тест-паззл</li><li>загрузка документа с ответом</li></ul><p>И SLA:</p><ul><li>загрузка страницы должна быть меньше 1 секунды</li><li>система должна выдерживать одновременную нагрузку 10000 учеников.</li></ul><h2 id="кеис-2-fintech" tabindex="-1">Кейс 2. FinTech <a class="header-anchor" href="#кеис-2-fintech" aria-label="Permalink to &quot;Кейс 2. FinTech&quot;">​</a></h2><p>Необходимо создать консоль управления SaaS-инфраструктурой для облачного сервиса и интеграцией с AD заказчика. Пользователь будет только один - генеральный директор компании, то есть продукт должен быть законченным и не содержать багов.</p><h2 id="кеис-3-proptech" tabindex="-1">Кейс 3. PropTech <a class="header-anchor" href="#кеис-3-proptech" aria-label="Permalink to &quot;Кейс 3. PropTech&quot;">​</a></h2><p>Необходимо создать облачное решение для планирования и технического надзора проектного строительства. Требования:</p><ul><li>Автономная работа без интернета</li><li>Умение работать с BIM (стандартизированный формат файлов для описания архитектуры здания)</li><li>Безопасность данных Задача - выстроить соответствия между конструкциями здания (водопровод, вентиляция, отделка, перекрытия) и конкретными подрядчиками, выполняющими данный вид работ.</li></ul><h2 id="кеис-4-hr-tech" tabindex="-1">Кейс 4. HR-Tech <a class="header-anchor" href="#кеис-4-hr-tech" aria-label="Permalink to &quot;Кейс 4. HR-Tech&quot;">​</a></h2><p>Необходимо создать продукт полного цикла для &quot;стаффинга&quot; - поиск и найм кандидатов, ведение личных дел, ознакомление с регламентами компании, фидбеки, интервью, распределение между проектами компании, API для получение информации из других систем и увольнение.</p><h2 id="кеис-5-личныи-блог-разработчика" tabindex="-1">Кейс 5. Личный блог разработчика <a class="header-anchor" href="#кеис-5-личныи-блог-разработчика" aria-label="Permalink to &quot;Кейс 5. Личный блог разработчика&quot;">​</a></h2><p>Полушуточный кейс - необходимо создать бесплатную среду для записи и публикации мыслей в которую будет удобно писать и обслуживание хостинга не должно занимать много времени.</p><hr><p>Чтобы не перегружать статью, мой субъективный выбор архитектуры для каждого кейса будет подробно расписан в следующих статьях.</p>',27)])])}const m=i(r,[["render",o]]);export{d as __pageData,m as default};
